  // Coverage Section (already present but keeping)
  coverageTitle: { EN: "Connected. Everywhere.", ES: "Conectados. En todas partes.", FR: "Connecté. Partout.", DE: "Verbunden. Überall.", RU: "На связи. Везде.", ZH: "连接。到处都是。", JA: "接続。どこでも。", PT: "Conectado. Em todos os lugares.", AR: "متصل. في كل مكان.", HI: "कनेक्टेड। हर जगह।" },
  coverageSubtitle1: { EN: "From cities to deserts, your signal follows you. 200+ countries, one private connection.", ES: "Desde ciudades hasta desiertos, tu señal te sigue. Más de 200 países, una conexión privada.", FR: "Des villes aux déserts, votre signal vous suit. 200+ pays, une connexion privée.", DE: "Von Städten bis Wüsten, dein Signal folgt dir. Über 200 Länder, eine private Verbindung.", RU: "От городов до пустынь, ваш сигнал следует за вами. Более 200 стран, одно частное подключение.", ZH: "从城市到沙漠，您的信号跟随您。200多个国家，一个私人连接。", JA: "都市から砂漠まで、あなたの信号はあなたを追いかけます。200か国以上、1つのプライベート接続。", PT: "De cidades a desertos, seu sinal o segue. Mais de 200 países, uma conexão privada.", AR: "من المدن إلى الصحاري، إشارتك تتبعك. أكثر من 200 دولة، اتصال خاص واحد.", HI: "शहरों से रेगिस्तानों तक, आपका सिग्नल आपका पीछा करता है। 200+ देश, एक निजी कनेक्शन।" },
  coverageSubtitle2: { EN: "One eSIM. The world is yours.", ES: "Una eSIM. El mundo es tuyo.", FR: "Une eSIM. Le monde vous appartient.", DE: "Eine eSIM. Die Welt gehört dir.", RU: "Одна eSIM. Мир твой.", ZH: "一张 eSIM。世界属于你。", JA: "1つのeSIM。世界はあなたのものです。", PT: "Um eSIM. O mundo é seu.", AR: "eSIM واحد. العالم ملكك.", HI: "एक eSIM। दुनिया आपकी है।" },
  coverageQuote: { EN: "Freedom means never losing signal — or yourself.", ES: "La libertad significa nunca perder la señal, ni a ti mismo.", FR: "La liberté signifie ne jamais perdre le signal — ou vous-même.", DE: "Freiheit bedeutet, niemals das Signal zu verlieren – oder sich selbst.", RU: "Свобода означает никогда не терять сигнал — или себя.", ZH: "自由意味着永不失去信号——或你自己。", JA: "自由とは、信号を失わないこと——そして自分自身を失わないことです。", PT: "Liberdade significa nunca perder o sinal — ou a si mesmo.", AR: "الحرية تعني عدم فقدان الإشارة أبدًا — أو نفسك.", HI: "स्वतंत्रता का मतलब कभी सिग्नल नहीं खोना है — या खुद को।" },
