  affiliateHero1: { EN: "Invite. Earn. Travel Together.", ES: "Invita. Gana. Viaja Juntos.", FR: "Invitez. Gagnez. Voyagez Ensemble.", DE: "Einladen. Verdienen. Zusammen Reisen.", RU: "Приглашай. Зарабатывай. Путешествуй Вместе.", ZH: "邀请。赚取。一起旅行。", JA: "招待。稼ぐ。一緒に旅行。", PT: "Convide. Ganhe. Viaje Juntos.", AR: "ادعُ. اربح. سافر معًا.", IT: "Invita. Guadagna. Viaggia Insieme." },
  affiliateHero2: { EN: "Join the borderless generation", ES: "Únete a la generación sin fronteras", FR: "Rejoignez la génération sans frontières", DE: "Tritt der grenzenlosen Generation bei", RU: "Присоединяйтесь к поколению без границ", ZH: "加入无国界世代", JA: "国境のない世代に参加", PT: "Junte-se à geração sem fronteiras", AR: "انضم إلى جيل بلا حدود", IT: "Unisciti alla generazione senza confini" },
  affiliateHero3: { EN: "Freedom is no longer physical — it's digital.", ES: "La libertad ya no es física, es digital.", FR: "La liberté n'est plus physique — elle est numérique.", DE: "Freiheit ist nicht mehr physisch — sie ist digital.", RU: "Свобода больше не физическая — она цифровая.", ZH: "自由不再是物理的——而是数字的。", JA: "自由はもはや物理的ではありません—デジタルです。", PT: "A liberdade não é mais física — é digital.", AR: "الحرية لم تعد مادية — إنها رقمية.", IT: "La libertà non è più fisica — è digitale." },
  
  affiliateStartTitle: { EN: "Start Earning Today", ES: "Comienza a Ganar Hoy", FR: "Commencez à Gagner Aujourd'hui", DE: "Beginne Heute zu Verdienen", RU: "Начните Зарабатывать Сегодня", ZH: "今天开始赚钱", JA: "今日から稼ぎ始める", PT: "Comece a Ganhar Hoje", AR: "ابدأ الكسب اليوم", IT: "Inizia a Guadagnare Oggi" },
  affiliateStartDesc: { EN: "Get your unique referral link instantly - no account required!", ES: "¡Obtén tu enlace de referencia único al instante, sin necesidad de cuenta!", FR: "Obtenez votre lien de parrainage unique instantanément - aucun compte requis !", DE: "Erhalte sofort deinen einzigartigen Empfehlungslink - kein Konto erforderlich!", RU: "Получите свою уникальную реферальную ссылку мгновенно - учетная запись не требуется!", ZH: "立即获取您的唯一推荐链接 - 无需帐户！", JA: "ユニークな紹介リンクを即座に取得 - アカウント不要！", PT: "Obtenha seu link de referência único instantaneamente - não é necessária conta!", AR: "احصل على رابط الإحالة الفريد الخاص بك على الفور - لا حاجة لحساب!", IT: "Ottieni il tuo link di referral unico istantaneamente - nessun account richiesto!" },
  
